import java.util.*;

public class Q4 {

    interface HealthIndicator { Health health(); }

    record Health(String status, Map<String, Object> details) {
        static Health up()   { return new Health("UP",   new LinkedHashMap<>()); }
        static Health down() { return new Health("DOWN", new LinkedHashMap<>()); }
        Health withDetail(String key, Object val) { details.put(key, val); return this; }
        boolean isUp() { return "UP".equals(status); }
        @Override public String toString() { return status + " " + details; }
    }

    static class ExternalApiHealth implements HealthIndicator {
        private final String url;
        ExternalApiHealth(String url) { this.url = url; }
        public Health health() {
            if (url.startsWith("https"))
                return Health.up().withDetail("url", url).withDetail("reachable", true);
            return Health.down().withDetail("url", url).withDetail("error", "insecure or unreachable");
        }
    }

    static class DiskSpaceHealth implements HealthIndicator {
        private final long freeBytes, thresholdBytes;
        DiskSpaceHealth(long free, long threshold) { freeBytes=free; thresholdBytes=threshold; }
        public Health health() {
            if (freeBytes >= thresholdBytes)
                return Health.up().withDetail("freeBytes", freeBytes);
            return Health.down().withDetail("freeBytes", freeBytes).withDetail("thresholdBytes", thresholdBytes);
        }
    }

    static Health aggregate(List<HealthIndicator> indicators) {
        boolean allUp = true;
        Map<String, Object> details = new LinkedHashMap<>();
        for (int i = 0; i < indicators.size(); i++) {
            Health h = indicators.get(i).health();
            details.put(indicators.get(i).getClass().getSimpleName() + "[" + i + "]", h.toString());
            if (!h.isUp()) allUp = false;
        }
        Health overall = allUp ? Health.up() : Health.down();
        overall.details().putAll(details);
        return overall;
    }

    public static void main(String[] args) {
        List<HealthIndicator> checks = List.of(
            new ExternalApiHealth("https://api.stripe.com/health"),
            new ExternalApiHealth("http://legacy.internal/api"),
            new DiskSpaceHealth(500_000_000L, 1_000_000_000L)
        );
        Health overall = aggregate(checks);
        System.out.println("Overall: " + overall.status());
        overall.details().forEach((k, v) -> System.out.println("  " + k + ": " + v));
    }
}

