import java.util.*;

public class Q6 {

    static Map<String, Object> beans = new LinkedHashMap<>();
    static Map<String, String> props = new HashMap<>();

    static boolean isMissing(String type) {
        return !beans.containsKey(type);
    }

    static boolean hasProperty(String key) {
        return props.containsKey(key);
    }

    static void autoConfigureMailService() {
        if (hasProperty("mail.host") && isMissing("MailService")) {
            beans.put("MailService", "AutoMailService[host=" + props.get("mail.host") + "]");
            System.out.println("Auto-configured MailService");
        } else {
            System.out.println("Skipped MailService auto-config: missing property or bean exists");
        }
    }

    static void autoConfigureDataSource() {
        if (hasProperty("datasource.url") && isMissing("DataSource")) {
            beans.put("DataSource", "AutoDataSource[url=" + props.get("datasource.url") + "]");
            System.out.println("Auto-configured DataSource");
        } else {
            System.out.println("Skipped DataSource auto-config: missing property or bean exists");
        }
    }

    public static void main(String[] args) {
        props.put("datasource.url", "jdbc:mysql://localhost/db");
        props.put("mail.host", "smtp.example.com");
        beans.put("DataSource", "UserDefinedDataSource");

        autoConfigureDataSource();
        autoConfigureMailService();
        System.out.println("DataSource: " + beans.get("DataSource"));
        System.out.println("MailService: " + beans.get("MailService"));

        System.out.println();
        beans.clear(); props.clear();
        props.put("datasource.url", "jdbc:h2:mem:test");
        autoConfigureDataSource();
        autoConfigureMailService();
        System.out.println("DataSource: " + beans.get("DataSource"));
        System.out.println("MailService: " + beans.getOrDefault("MailService", "NOT_CREATED"));
    }
}

