import java.util.*;

public class Q7 {

    record UserRegisteredEvent(String userId, String email) {}

    interface EventPublisher { void publishEvent(Object event); }

    static class SimpleEventBus implements EventPublisher {
        private final List<Object> listeners = new ArrayList<>();
        void register(Object listener) { listeners.add(listener); }
        public void publishEvent(Object event) {
            for (Object listener : listeners) {
                if (listener instanceof UserRegisteredListener l && event instanceof UserRegisteredEvent e)
                    l.onUserRegistered(e);
            }
        }
    }

    interface UserRegisteredListener {
        void onUserRegistered(UserRegisteredEvent event);
    }

    static class EmailNotificationListener implements UserRegisteredListener {
        public void onUserRegistered(UserRegisteredEvent e) {
            System.out.println("[Email] Sending welcome to " + e.email());
        }
    }

    static class AuditLogListener implements UserRegisteredListener {
        public void onUserRegistered(UserRegisteredEvent e) {
            System.out.println("[Audit] User " + e.userId() + " registered at " + System.currentTimeMillis());
        }
    }

    static class UserService {
        private final EventPublisher publisher;
        UserService(EventPublisher pub) { this.publisher = pub; }
        void register(String userId, String email) {
            System.out.println("Registered user: " + userId);
            publisher.publishEvent(new UserRegisteredEvent(userId, email));
        }
    }

    public static void main(String[] args) {
        SimpleEventBus bus = new SimpleEventBus();
        bus.register(new EmailNotificationListener());
        bus.register(new AuditLogListener());
        UserService service = new UserService(bus);
        service.register("usr-001", "alice@example.com");
    }
}
